import './TablePagination.scss';

import { Select } from ':components/Select/Select';
import { useDeviceSize } from ':helpers';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React, { useEffect, useMemo, useState } from 'react';

import { classNames, classNames as cn } from '../../helpers/classnames';
import { IconButton } from '../IconButton';
import { Typography } from '../Typography';
import type { TablePaginationProps } from './TablePagination.types';
import { getPageCount } from './TablePagination.utils';

export const TablePagination: FC<TablePaginationProps> = ({
	label,
	rowsCount,
	page = 1,
	rowsPerPage = 5,
	rowsPerPageOptions = [5, 10, 25, 50, 100],
	onPageChange,
	onRowsPerPageChange,
	onUserActions,
	showFirstAndLastButtons = false,
	className,
	...props
}) => {
	const { isExtraSmallDevice } = useDeviceSize();

	useEffect(() => {
		if (onPageChange) {
			console.warn('[TablePagination] props "onPageChange" is deprecated, use "onUserActions" instead');
		}

		if (onRowsPerPageChange) {
			console.warn('[TablePagination] props "onRowsPerPageChange" is deprecated, use "onUserActions" instead');
		}
	}, [onPageChange, onRowsPerPageChange]);

	const [_rowsPerPage, _setRowsPerPage] = useState<number>(rowsPerPage);
	const [pagesCount, setPagesCount] = useState<number>(0);
	const [selectedOptions, setSelectedOptions] = useState<number[]>([rowsPerPage]);

	const showedRange = useMemo(
		() => `${page * _rowsPerPage - _rowsPerPage + 1}-${Math.min(_rowsPerPage * page, rowsCount)}`,
		[page, _rowsPerPage, rowsCount],
	);

	useEffect(() => {
		// Обновляем количество страниц (кол. строк \ кол. строк на страницу)
		setPagesCount(getPageCount(rowsCount, rowsPerPage));

		// Обновляем количество страниц (кол. строк \ кол. строк на страницу)
		setSelectedOptions([rowsPerPage]);
		_setRowsPerPage(rowsPerPage);
	}, [rowsPerPage, rowsCount]);

	const handleRowsPerPageChange = (values: number[] & string[]): void => {
		const currentRowsPerPage = values[0];

		setSelectedOptions(values);
		_setRowsPerPage(currentRowsPerPage);

		// Обновляем количество страниц (кол. строк \ кол. строк на страницу)
		setPagesCount(getPageCount(rowsCount, currentRowsPerPage));

		let newPage = page;

		// Обновляем текущую страницу ~ попасть на те строки, которые отображались до изменения в селекте.
		if (page > 1) {
			newPage = Math.ceil(((page - 1) * _rowsPerPage + 1) / currentRowsPerPage);
		}

		onUserActions?.({
			page: newPage,
			rowsPerPage: currentRowsPerPage,
		});

		onPageChange?.(newPage);
		onRowsPerPageChange?.(currentRowsPerPage);
	};

	const handleSetFirstPage = (): void => {
		onPageChange?.(1);

		onUserActions?.({
			page: 1,
			rowsPerPage,
		});
	};

	const handleSetLastPage = (): void => {
		onPageChange?.(pagesCount);

		onUserActions?.({
			page: pagesCount,
			rowsPerPage,
		});
	};

	const handleForwardClick = (): void => {
		const newPage = Math.min(page + 1, pagesCount);
		onPageChange?.(newPage);

		onUserActions?.({
			page: newPage,
			rowsPerPage,
		});
	};

	const handleBackwardClick = (): void => {
		const newPage = Math.max(page - 1, 1);
		onPageChange?.(newPage);

		onUserActions?.({
			page: newPage,
			rowsPerPage,
		});
	};

	return (
		<div
			data-testid="TablePagination"
			className={cn('dsb_table-pagination', className, isExtraSmallDevice && 'dsb_table-pagination-mobile')}
			{...props}
		>
			{!isExtraSmallDevice &&
				(label || (
					<Typography variant="body3" className="dsb_table-pagination-rows-per-page-text">
						Строк на странице:
					</Typography>
				))}

			<Select
				size="small"
				className="dsb_table-pagination-rows-per-page-select"
				values={selectedOptions.map(value => value.toString())}
				options={rowsPerPageOptions.map(option => option.toString())}
				onChange={handleRowsPerPageChange}
				showTooltip={false}
				renderValue={isExtraSmallDevice ? values => `${values.join('')} из ${rowsCount}` : undefined}
			/>

			{!isExtraSmallDevice && (
				<Typography className="dsb_table-pagination-pages-count" variant="body3">
					{`${showedRange} из ${rowsCount}`}
				</Typography>
			)}

			<div className="dsb_table-pagination__controls">
				{showFirstAndLastButtons && (
					<IconButton
						className="dsb_table-pagination-scroll-first"
						disabled={page === 1}
						iconName={Icons.FastArrowLeft}
						size="large"
						onClick={handleSetFirstPage}
					/>
				)}
				<IconButton
					className="dsb_table-pagination-scroll-backward"
					disabled={page === 1}
					iconName={Icons.ArrowLeft}
					size="large"
					onClick={handleBackwardClick}
				/>
				{isExtraSmallDevice && (
					<Typography className="dsb_table-pagination-pages-count" variant="body3">
						{`${showedRange}`}
					</Typography>
				)}
				<IconButton
					className="dsb_table-pagination-scroll-forward"
					disabled={page === pagesCount}
					iconName={Icons.ArrowRight}
					size="large"
					onClick={handleForwardClick}
				/>
				{showFirstAndLastButtons && (
					<IconButton
						className="dsb_table-pagination-scroll-last"
						disabled={page === pagesCount}
						iconName={Icons.FastArrowRight}
						size="large"
						onClick={handleSetLastPage}
					/>
				)}
			</div>
		</div>
	);
};
